#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long N,K,X; scanf("%lld %lld %lld",&N,&K,&X);
        long long sum=0; // minimal sum of first K-1 elements
        for(long long i=1;i< K;i++){
            if(sum > X) break; // already larger than X, no need to continue
            // sum = 2^{i-1} - 1 grows as sum = sum*2 + 1
            if(sum > (X+1)/2) sum = X+1; // cap to avoid overflow
            else sum = sum*2 + 1;
        }
        if(X > sum) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

