import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it)); X = int(next(it))
        s = 0
        # compute minimal sum of first K-1 elements, capped at X+1
        for i in range(1, K):
            if s > X:
                break
            if s > (X + 1) // 2:
                s = X + 1
            else:
                s = s * 2 + 1
        out.append('Yes' if X > s else 'No')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

